#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
struct node {
	int l1, r1, l2, r2;
} a[200005];
int n;
bool cmp (node x, node y) {
	if (x.l2 == y.l2) {
		return x.r2 < y.r2;
	}
	return x.l2<y.l2;
}
bool check (int x) {
	int s1 = 0, s2 = 0;
	for (int i = 1; i <= n; i++) {
		if (a[i].l2 > x) {
			s2 += a[i].l1;
		} else {
			s1 += a[i].r1;
		}
	}
	if ((s1 + s2) % 2 == 0) {
		return s1 >= s2;
	} else {
		return s1 >= (s2 + 1);
	}
}
bool check2 (int x) {
	int s1 = 0, s2 = 0;
	for (int i = 1; i <= n; i++) {
		if (a[i].r2 < x) {
			s1 += a[i].l1;
		} else {
			s2 += a[i].r1;
		}
	}
	if ((s1 + s2) % 2 == 0) {
		return s2 >= s1 + 2;
	} else {
		return s2 >= s1 + 1;
	}
}
signed main() {
	int c, t;
	cin >> c >> t;
	while (t--) {
		cin >> n;
		int maxk;
		for (int i = 1; i <= n; i++) {
			cin >> a[i].l1 >> a[i].r1 >> a[i].l2 >> a[i].r2;
			maxk = max (a[i].r2, maxk);
		}
		int l1 = maxk, r1 = 0;
		while (l1 > r1) {
			int mid = (l1 + r1 - 1) / 2;
			if (check (mid)) {
				l1 = mid;
			} else {
				r1 = mid + 1;
			}
		}
		int l2 = 0, r2 = maxk;
		while (l2 < r2) {
			int mid = (l2 + r2 + 1) / 2;
			if (check2 (mid)) {
				l2 = mid;
			} else {
				r2 = mid - 1;
			}
		}
		sort (a + 1, a + 1 + n, cmp);
		int s1 = a[1].l2, s2 = a[1].r2;
		int ans = 0;
		for (int i = 2; i <= n; i++) {
			if (a[i].l2 <= s2) {
				s2 = max (s2, a[i].r2);
			} else {
				if (s2 >= l2 && s1 <= l2) {
					ans = ans + (l2 - max (s1, l1) + 1);
				}
				else if (s2 <= l2 && s2 >= l1) {
					ans = ans + (s2 - max (s1, l1) + 1);
				}
				s1 = a[i].l2;
				s2 = a[i].r2;
			}
		}
		if (s2 >= l2 && s1 <= l2) {
			ans = ans + (l2 - max (s1, l1) + 1);
		} else if (s2 <= l2 && s2 >= l1) {
			ans = ans + (s2 - max (s1, l1) + 1);
		}
		cout << ans << '\n';
	}	
	return 0;
}
